import { Github, Linkedin, Twitter, Instagram, CodepenIcon } from "lucide-react"

const socialLinks = [
  { icon: Github, href: "https://github.com/MrSalaam", label: "GitHub" },
  { icon: Instagram, href: "https://instagram.com/", label: "Instagram" },
  { icon: Twitter, href: "https://x.com/OlayinkaSZN", label: "Twitter" },
  { icon: Linkedin, href: "https://linkedin.com/in/olayinka-salaam", label: "LinkedIn" },
  { icon: CodepenIcon, href: "https://codepen.io", label: "CodePen" },
]

export function Footer() {
  return (
    <footer className="border-t border-border py-8 md:py-12 mt-20">
      <div className="flex flex-col md:flex-row justify-between items-center gap-8 px-4 md:px-0">
        <div className="flex items-center gap-6">
          {socialLinks.map((link) => (
            <a
              key={link.label}
              href={link.href}
              target="_blank"
              rel="noopener noreferrer"
              className="text-foreground/50 hover:text-foreground transition-colors"
              aria-label={link.label}
            >
              <link.icon className="w-5 h-5 stroke-[1.5]" />
            </a>
          ))}
        </div>
        <div className="text-center md:text-right font-sans text-xs tracking-widest uppercase text-foreground/40">
          <div>© {new Date().getFullYear()} Yinka Salaam.</div>
          <div className="mt-2">All rights reserved.</div>
        </div>
      </div>
    </footer>
  )
}
