"use client"

import { useRef } from "react"
import { motion, useInView } from "framer-motion"

const skillCategories = [
  {
    title: "Languages",
    skills: ["TypeScript", "JavaScript", "HTML", "CSS"],
  },
  {
    title: "Frameworks & Libraries",
    skills: ["React", "Next.js", "Node.js", "Express", "Tailwind CSS", "Framer Motion", "GSAP", "TanStack Query"],
  },
  {
    title: "Tools & DevOps",
    skills: ["Git", "GitHub", "Vercel", "Figma", "VS Code"],
  },
]

export function SkillsSection() {
  return (
    <section id="skills" className="py-24 md:py-32 scroll-mt-20 border-t border-border">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-8 mb-16 px-4 md:px-0">
        <div>
          <h2 className="text-4xl md:text-5xl font-serif text-foreground tracking-tight mb-4">
            Capabilities
          </h2>
          <p className="font-sans text-xs tracking-widest uppercase text-foreground/40">
            03 — The Toolkit
          </p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 bg-border border-y border-border gap-px">
        {skillCategories.map((category) => (
          <div key={category.title} className="bg-background p-8 md:p-12 flex flex-col justify-between aspect-square group hover:bg-muted transition-colors duration-500">
            <h3 className="font-serif text-2xl text-foreground">
              {category.title}
            </h3>
            
            <ul className="space-y-3 mt-12">
              {category.skills.map((skill) => (
                <li key={skill} className="font-sans text-sm text-foreground/70 group-hover:text-foreground transition-colors flex items-center gap-3">
                  <span className="w-4 h-px bg-foreground/20 group-hover:bg-foreground/40 transition-colors"></span>
                  {skill}
                </li>
              ))}
            </ul>
          </div>
        ))}
      </div>
    </section>
  )
}
