export function ProjectsSection() {
  return (
    <section id="projects" className="py-24 md:py-32 scroll-mt-20 border-t border-border">
      <div className="flex flex-col items-center text-center space-y-6 mb-20">
        <h2 className="text-4xl md:text-5xl font-serif text-foreground tracking-tight">
          Selected Works
        </h2>
        <p className="font-sans text-xs tracking-widest uppercase text-foreground/40">
          02 — The Archive
        </p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-8 px-4 md:px-0">
        {[1, 2, 3].map((i) => (
          <div key={i} className={`aspect-square bg-secondary border border-border group relative overflow-hidden flex flex-col justify-between p-8 hover:bg-muted transition-colors duration-500 ${i % 2 === 0 ? 'md:translate-y-16' : ''}`}>
            <div className="flex justify-between items-start w-full">
              <span className="font-sans text-xs tracking-widest uppercase text-foreground/50">In Progress</span>
              <span className="w-2 h-2 bg-foreground/20 group-hover:bg-foreground transition-colors duration-500"></span>
            </div>
            
            <div className="space-y-4">
              <h3 className="text-2xl font-serif text-foreground">Project 0{i}</h3>
              <p className="text-foreground/60 font-sans text-sm">
                A pristine digital experience. Currently under construction in the laboratory.
              </p>
            </div>
          </div>
        ))}
      </div>
    </section>
  )
}
