"use client"

import type React from "react"
import { useState } from "react"
import { ArrowRightIcon } from "@radix-ui/react-icons"

export function ContactSection() {
  const [formState, setFormState] = useState({ name: "", email: "", message: "" })
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [isSuccess, setIsSuccess] = useState(false)

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setIsSubmitting(true)
    await new Promise(resolve => setTimeout(resolve, 1500))
    setIsSubmitting(false)
    setIsSuccess(true)
    setTimeout(() => {
      setIsSuccess(false)
      setFormState({ name: "", email: "", message: "" })
    }, 3000)
  }

  return (
    <section id="contact" className="py-24 md:py-32 scroll-mt-20 border-t border-border">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-8 mb-16 px-4 md:px-0">
        <div>
          <h2 className="text-4xl md:text-5xl font-serif text-foreground tracking-tight mb-4">
            Contact
          </h2>
          <p className="font-sans text-xs tracking-widest uppercase text-foreground/40">
            05 — Get In Touch
          </p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-12 gap-16 md:gap-8 px-4 md:px-0">
        <div className="md:col-span-5 space-y-8">
          <p className="text-xl md:text-2xl font-serif text-foreground leading-relaxed">
            I'm currently looking for new opportunities. Whether you have a question or just want to say hi, I'll try my best to get back to you.
          </p>
          <a
            href="mailto:olayinkasalaam.dev@gmail.com"
            className="inline-block text-2xl md:text-4xl font-serif text-foreground hover:text-foreground/70 transition-colors border-b border-foreground pb-2"
          >
            hello@yinkasalaam.com
          </a>
        </div>

        <div className="md:col-span-6 md:col-start-7">
          <form onSubmit={handleSubmit} className="space-y-8">
            <div className="space-y-2">
              <label htmlFor="name" className="text-xs font-sans tracking-widest uppercase text-foreground/60">Name</label>
              <input
                id="name"
                value={formState.name}
                onChange={(e) => setFormState({ ...formState, name: e.target.value })}
                className="w-full bg-transparent border-b border-border focus:border-foreground py-4 text-lg font-sans outline-none transition-colors rounded-none"
                placeholder="John Doe"
                required
              />
            </div>
            <div className="space-y-2">
              <label htmlFor="email" className="text-xs font-sans tracking-widest uppercase text-foreground/60">Email</label>
              <input
                id="email"
                type="email"
                value={formState.email}
                onChange={(e) => setFormState({ ...formState, email: e.target.value })}
                className="w-full bg-transparent border-b border-border focus:border-foreground py-4 text-lg font-sans outline-none transition-colors rounded-none"
                placeholder="john@example.com"
                required
              />
            </div>
            <div className="space-y-2">
              <label htmlFor="message" className="text-xs font-sans tracking-widest uppercase text-foreground/60">Message</label>
              <textarea
                id="message"
                value={formState.message}
                onChange={(e) => setFormState({ ...formState, message: e.target.value })}
                className="w-full bg-transparent border-b border-border focus:border-foreground py-4 text-lg font-sans outline-none transition-colors resize-none rounded-none"
                placeholder="Hello Yinka..."
                rows={4}
                required
              />
            </div>
            <button
              type="submit"
              disabled={isSubmitting || isSuccess}
              className={`inline-flex items-center gap-4 text-xs font-sans tracking-widest uppercase py-4 group ${isSuccess ? "text-green-600" : "text-foreground"}`}
            >
              {isSubmitting ? "Sending..." : isSuccess ? "Message Sent" : "Send Message"}
              {!isSubmitting && !isSuccess && <ArrowRightIcon className="w-4 h-4 group-hover:translate-x-2 transition-transform" />}
            </button>
          </form>
        </div>
      </div>
    </section>
  )
}
